// do executes an HTTP request. headerOverrides, when non-nil, override global
// RequiredHeaders for this specific request (used for per-endpoint API versioning).
// buildFormBody converts a body map and the AUTH_ID credential into a
// application/x-www-form-urlencoded byte slice. The IPA /public-ws/ endpoints
// require all parameters (including AUTH_ID) to be in the POST form body; they
// reject AUTH_ID passed as a query string or JSON body.
func buildFormBody(authID string, body any) []byte {
	form := url.Values{}
	if authID != "" {
		form.Set("AUTH_ID", authID)
	}
	if body != nil {
		if m, ok := body.(map[string]any); ok {
			for k, v := range m {
				if v != nil {
					form.Set(k, fmt.Sprintf("%v", v))
				}
			}
		}
	}
	return []byte(form.Encode())
}

func (c *Client) do(method, path string, params map[string]string, body any, headerOverrides map[string]string) (json.RawMessage, int, error) {
	targetURL := c.BaseURL + path

	// Resolve auth material before the dry-run branch so --dry-run can preview
	// exactly what would be sent.
	authHeader, err := c.authHeader()
	if err != nil {
		return nil, 0, err
	}

	// IPA /public-ws/ endpoints require POST with application/x-www-form-urlencoded
	// body that includes AUTH_ID. JSON body and query-param auth are both rejected.
	var bodyBytes []byte
	isFormPost := method == "POST" || method == "PUT" || method == "PATCH"
	if isFormPost {
		bodyBytes = buildFormBody(authHeader, body)
	} else if body != nil {
		b, err := json.Marshal(body)
		if err != nil {
			return nil, 0, fmt.Errorf("marshaling body: %w", err)
		}
		bodyBytes = b
	}

	// Build the request for dry-run display or actual execution
	if c.DryRun {
		return c.dryRun(method, targetURL, path, params, bodyBytes, headerOverrides, authHeader)
	}

	const maxRetries = 3
	var lastErr error

	for attempt := 0; attempt <= maxRetries; attempt++ {
		// Proactive rate limiting — wait before sending
		c.limiter.Wait()
		var bodyReader io.Reader
		if bodyBytes != nil {
			bodyReader = strings.NewReader(string(bodyBytes))
		}

		req, err := http.NewRequest(method, targetURL, bodyReader)
		if err != nil {
			return nil, 0, fmt.Errorf("creating request: %w", err)
		}
		if bodyBytes != nil {
			if isFormPost {
				req.Header.Set("Content-Type", "application/x-www-form-urlencoded")
			} else {
				req.Header.Set("Content-Type", "application/json")
			}
		}

		if params != nil {
			q := req.URL.Query()
			for k, v := range params {
				if v != "" {
					q.Set(k, v)
				}
			}
			req.URL.RawQuery = q.Encode()
		}

		// AUTH_ID is already included in the form body for POST/PUT/PATCH;
		// only add to query string for GET/DELETE requests (not used by IPA).
		if authHeader != "" && !isFormPost {
			q := req.URL.Query()
			q.Set("AUTH_ID", authHeader)
			req.URL.RawQuery = q.Encode()
		}
		if c.Config != nil {
			for k, v := range c.Config.Headers {
				req.Header.Set(k, v)
			}
		}
		// Per-endpoint header overrides (e.g., different API version per resource)
		for k, v := range headerOverrides {
			req.Header.Set(k, v)
		}
		if req.Header.Get("User-Agent") == "" {
			req.Header.Set("User-Agent", "github.com/mvanhorn/printing-press-library/library/developer-tools/openipa/0.1.0")
		}
		// Go's net/http omits Accept by default; browsers, curl, and other
		// stdlibs always send it. Fingerprint-checking WAFs (Imperva, Akamai,
		// Cloudflare bot-mode, DataDome) flag the absence as a bot signal
		// and answer with empty-body 5xx, 403, or a challenge redirect
		// depending on vendor and rule tier. The value is application/json
		// rather than */* because strict-JSON APIs (Zendesk, Atlassian REST,
		// Salesforce) return 415 on anything that isn't literally
		// application/json; specs that need a different content type
		// (vendor mediatypes, XML, HTML) declare it via RequiredHeaders or
		// per-endpoint headerOverrides, both of which run before this
		// if-empty default.
		if req.Header.Get("Accept") == "" {
			req.Header.Set("Accept", "application/json")
		}

		resp, err := c.HTTPClient.Do(req)
		if err != nil {
			lastErr = fmt.Errorf("%s %s: %w", method, path, err)
			continue
		}

		respBody, err := io.ReadAll(resp.Body)
		resp.Body.Close()
		if err != nil {
			return nil, 0, fmt.Errorf("reading response: %w", err)
		}
		respBody = sanitizeJSONResponse(respBody)

		// Success
		if resp.StatusCode < 400 {
			c.limiter.OnSuccess()
			if method != http.MethodGet && !c.DryRun {
				c.invalidateCache()
			}
			return json.RawMessage(respBody), resp.StatusCode, nil
		}

		apiErr := &APIError{
			Method:     method,
			Path:       path,
			StatusCode: resp.StatusCode,
			Body:       truncateBody(respBody),
		}

		// Rate limited - adjust adaptive limiter and retry
		if resp.StatusCode == 429 && attempt < maxRetries {
			c.limiter.OnRateLimit()
			wait := cliutil.RetryAfter(resp)
			fmt.Fprintf(os.Stderr, "rate limited, waiting %s (attempt %d/%d, rate adjusted to %.1f req/s)\n", wait, attempt+1, maxRetries, c.limiter.Rate())
			time.Sleep(wait)
			lastErr = apiErr
			continue
		}

		// Server error - retry with backoff
		if resp.StatusCode >= 500 && attempt < maxRetries {
			wait := time.Duration(math.Pow(2, float64(attempt))) * time.Second
			fmt.Fprintf(os.Stderr, "server error %d, retrying in %s (attempt %d/%d)\n", resp.StatusCode, wait, attempt+1, maxRetries)
			time.Sleep(wait)
			lastErr = apiErr
			continue
		}

		// Client error or retries exhausted - return the error
		return nil, resp.StatusCode, apiErr
	}

	return nil, 0, lastErr
}

// dryRun prints the outgoing request exactly as the live path would send it,
// using the auth material already resolved in `do()`. Never triggers a network
// call — the caller is responsible for passing cached auth material only.
func (c *Client) dryRun(method, targetURL, path string, params map[string]string, body []byte, headerOverrides map[string]string, authHeader string) (json.RawMessage, int, error) {
	fmt.Fprintf(os.Stderr, "%s %s\n", method, targetURL)
	queryPrinted := false
	if params != nil {
		keys := make([]string, 0, len(params))
		for k := range params {
			if params[k] != "" {
				keys = append(keys, k)
			}
		}
		sort.Strings(keys)
		for _, k := range keys {
			sep := "?"
			if queryPrinted {
				sep = "&"
			}
			fmt.Fprintf(os.Stderr, "  %s%s=%s\n", sep, k, params[k])
			queryPrinted = true
		}
	}
	isFormPost := method == "POST" || method == "PUT" || method == "PATCH"

	// For GET/DELETE, AUTH_ID travels as a query string parameter.
	// For POST/PUT/PATCH it is already embedded in the form body via buildFormBody.
	if authHeader != "" && !isFormPost {
		sep := "?"
		if queryPrinted {
			sep = "&"
		}
		fmt.Fprintf(os.Stderr, "  %s%s=%s\n", sep, "AUTH_ID", maskToken(authHeader))
		queryPrinted = true
	}
	_ = queryPrinted
	if body != nil {
		if isFormPost {
			if vals, err := url.ParseQuery(string(body)); err == nil {
				fmt.Fprintf(os.Stderr, "  Body (form):\n")
				keys := make([]string, 0, len(vals))
				for k := range vals {
					keys = append(keys, k)
				}
				sort.Strings(keys)
				for _, k := range keys {
					v := vals.Get(k)
					if k == "AUTH_ID" {
						v = maskToken(v)
					}
					fmt.Fprintf(os.Stderr, "    %s=%s\n", k, v)
				}
			}
		} else {
			var pretty json.RawMessage
			if json.Unmarshal(body, &pretty) == nil {
				enc := json.NewEncoder(os.Stderr)
				enc.SetIndent("  ", "  ")
				fmt.Fprintf(os.Stderr, "  Body:\n")
				_ = enc.Encode(pretty)
			}
		}
	}
	fmt.Fprintf(os.Stderr, "\n(dry run - no request sent)\n")
	return json.RawMessage(`{"dry_run": true}`), 0, nil
}

